        root = ET.fromstring(res.content)
        news_html = ""
        for item in root.findall('./channel/item')[:6]:
            title = item.find('title').text; clean_title = title.rsplit(" - ", 1)[0]
            source = title.rsplit(" - ", 1)[-1] if " - " in title else "Macro News"
            link = item.find('link').text; pubDate = item.find('pubDate').text
